void test_error_empty_language_name(void) {
    /* Parsing with empty language name should error */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"\"}");
    TS_PACKProcessResult* result = ts_pack_process("hello", options_handle);
    ts_pack_process_config_free(options_handle);
    assert(result == NULL && "expected call to fail");
}

void test_error_handling_empty_source(void) {
    /* Parsing an empty string should still produce a tree. */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"javascript\"}");
    TS_PACKProcessResult* result = ts_pack_process("", options_handle);
    assert(result != NULL && "expected call to succeed");
    ts_pack_process_config_free(options_handle);
    ts_pack_process_result_free(result);
}

void test_error_handling_get_language_empty_string(void) {
    /* get_language with empty string returns an error */
    TS_PACKLanguage* result = ts_pack_get_language("");
    assert(result == NULL && "expected call to fail");
}

void test_error_handling_haskell_unterminated_block_comment(void) {
    /* Regression: unterminated nested Haskell block comment must not crash the process. On gcc/aarch64 at -O2 with a pre-0.26.4 vendored array.h and without -fno-strict-aliasing, this input triggers heap corruption (malloc: mismatching next->prev_size) via a strict-aliasing miscompilation in the scanner's array_push hot loop. */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"haskell\"}");
    TS_PACKProcessResult* result = ts_pack_process("{-aaaaaaaaaaaaaa aaaa}\n    {-aaa (aaaaaaaaaa [aaaaaaaaaaaaa aaa", options_handle);
    assert(result != NULL && "expected call to succeed");
    ts_pack_process_config_free(options_handle);
    ts_pack_process_result_free(result);
}

