void test_error_handling_invalid_syntax(void) {
    /* Parsing invalid syntax should produce a tree with error nodes. */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"javascript\"}");
    TS_PACKProcessResult* result = ts_pack_process("function function function @@@ %%%", options_handle);
    assert(result != NULL && "expected call to succeed");
    ts_pack_process_config_free(options_handle);
    ts_pack_process_result_free(result);
}

void test_error_handling_unknown_language(void) {
    /* Loading a nonexistent language should produce an error. */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"nonexistent_xyz\"}");
    TS_PACKProcessResult* result = ts_pack_process("", options_handle);
    ts_pack_process_config_free(options_handle);
    assert(result == NULL && "expected call to fail");
}

void test_error_process_empty_source(void) {
    /* Process empty source code succeeds with zero metrics */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"python\"}");
    TS_PACKProcessResult* result = ts_pack_process("", options_handle);
    assert(result != NULL && "expected call to succeed");
    char* metrics_total_lines = ts_pack_process_result_total_lines(result);
    assert(strcmp(metrics_total_lines, 0) == 0 && "equals assertion failed");
    ts_pack_free_string(metrics_total_lines);
    ts_pack_process_config_free(options_handle);
    ts_pack_process_result_free(result);
}

void test_parse_empty_language(void) {
    /* process() returns error with empty language name */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"\"}");
    TS_PACKProcessResult* result = ts_pack_process("x = 1", options_handle);
    ts_pack_process_config_free(options_handle);
    assert(result == NULL && "expected call to fail");
}

void test_process_unknown_language(void) {
    /* process() returns error when config language is unknown */
    TS_PACKProcessConfig* options_handle = ts_pack_process_config_from_json("{\"language\":\"nonexistent_xyz\"}");
    TS_PACKProcessResult* result = ts_pack_process("x = 1", options_handle);
    ts_pack_process_config_free(options_handle);
    assert(result == NULL && "expected call to fail");
}
